package directory

import "testing"

func TestSlugTrimsTabPadding(t *testing.T) {
	if got := Slug("\t Ballroom \t"); got != "ballroom" {
		t.Fatalf("Slug(%q) = %q, want %q", "\t Ballroom \t", got, "ballroom")
	}
}

func TestSlugLowercasesAllCaps(t *testing.T) {
	if got := Slug("LOFT"); got != "loft" {
		t.Fatalf("Slug(%q) = %q, want %q", "LOFT", got, "loft")
	}
}
